CREATE TRIGGER LG_CLFLINE_INS_323_02 ON LG_323_02_CLFLINE
FOR INSERT
AS
DECLARE @DT         DATETIME
DECLARE @MONTH      SMALLINT
DECLARE @YEAR       SMALLINT
DECLARE @TRCODE     SMALLINT
DECLARE @SIGN       SMALLINT
DECLARE @AMOUNT     FLOAT
DECLARE @REPORTNET  FLOAT
DECLARE @CLIENTREF  INT
DECLARE @MODULENR   SMALLINT
DECLARE @CANCELLED  SMALLINT
DECLARE @REPORTRATE FLOAT
DECLARE @SOURCEFREF INT
DECLARE @STATUS     SMALLINT
DECLARE @AFFECTCOLLATRL   SMALLINT
DECLARE @AFFECTRISK   SMALLINT
SELECT @DT = I.DATE_,
       @MONTH  = I.MONTH_,
       @YEAR   = I.YEAR_,
       @TRCODE = I.TRCODE,
       @SIGN = I.SIGN,
       @AMOUNT = I.AMOUNT,
       @REPORTNET = I.REPORTNET,
       @CLIENTREF = I.CLIENTREF,
       @MODULENR = I.MODULENR,
       @CANCELLED = I.CANCELLED,
       @REPORTRATE = I.REPORTRATE,
       @SOURCEFREF = I.SOURCEFREF,
       @STATUS = I.STATUS,
       @AFFECTCOLLATRL =I.AFFECTCOLLATRL,
       @AFFECTRISK =I.AFFECTRISK FROM INSERTED I
EXECUTE LG_UPDATE_CLTRANS_323_02 1, @DT, @TRCODE, @SIGN, @AMOUNT, @REPORTNET, @CLIENTREF,
                                 @MODULENR, @CANCELLED, @REPORTRATE, @SOURCEFREF, @STATUS,
                                 @MONTH, @YEAR, @AFFECTCOLLATRL, @AFFECTRISK
